import os
import sys
import shlex
import getpass
import datetime
from typing import List


def _cmd_ls(args: List[str]) -> str:
    path = args[1] if len(args) > 1 else "."
    try:
        entries = os.listdir(path)
        entries.sort()
        return "\n".join(entries)
    except OSError as e:
        raise RuntimeError(f"ls error: {e.strerror}") from e


def _cmd_pwd(_: List[str]) -> str:
    return os.getcwd()


def _cmd_whoami(_: List[str]) -> str:
    return getpass.getuser()


def _cmd_date(_: List[str]) -> str:
    return datetime.datetime.now().strftime("%a %b %d %H:%M:%S %Z %Y")


def _cmd_echo(args: List[str]) -> str:
    return " ".join(args[1:])


def _read_file(path: str) -> List[str]:
    try:
        with open(path, "r", encoding="utf-8", errors="replace") as f:
            return f.readlines()
    except OSError as e:
        raise RuntimeError(f"file error: {e.strerror}") from e


def _cmd_cat(args: List[str]) -> str:
    if len(args) == 1:
        raise RuntimeError("cat error: no file specified")
    lines = []
    for filename in args[1:]:
        lines.extend(_read_file(filename))
    return "".join(lines).rstrip("\n")


def _cmd_head(args: List[str]) -> str:
    if len(args) == 1:
        raise RuntimeError("head error: no file specified")
    count = 10
    files = args[1:]
    if files[0].isdigit():
        count = int(files[0])
        files = files[1:]
    if not files:
        raise RuntimeError("head error: no file specified")
    lines = []
    for filename in files:
        lines.extend(_read_file(filename)[:count])
    return "".join(lines).rstrip("\n")


def _cmd_tail(args: List[str]) -> str:
    if len(args) == 1:
        raise RuntimeError("tail error: no file specified")
    count = 10
    files = args[1:]
    if files[0].isdigit():
        count = int(files[0])
        files = files[1:]
    if not files:
        raise RuntimeError("tail error: no file specified")
    lines = []
    for filename in files:
        lines.extend(_read_file(filename)[-count:])
    return "".join(lines).rstrip("\n")


def _cmd_grep(args: List[str]) -> str:
    if len(args) < 3:
        raise RuntimeError("grep error: usage grep <pattern> <file> [file...]")
    pattern = args[1]
    files = args[2:]
    matched = []
    for filename in files:
        for line in _read_file(filename):
            if pattern in line:
                matched.append(line.rstrip("\n"))
    return "\n".join(matched)


def _cmd_uptime(_: List[str]) -> str:
    if sys.platform.startswith("linux"):
        try:
            with open("/proc/uptime", "r", encoding="utf-8") as f:
                seconds = float(f.read().split()[0])
                mins, secs = divmod(int(seconds), 60)
                hrs, mins = divmod(mins, 60)
                days, hrs = divmod(hrs, 24)
                parts = []
                if days:
                    parts.append(f"{days} day{'s' if days != 1 else ''}")
                if hrs:
                    parts.append(f"{hrs} hour{'s' if hrs != 1 else ''}")
                if mins:
                    parts.append(f"{mins} minute{'s' if mins != 1 else ''}")
                parts.append(f"{secs} second{'s' if secs != 1 else ''}")
                return ", ".join(parts) + " up"
        except OSError as e:
            raise RuntimeError(f"uptime error: {e.strerror}") from e
    else:
        return datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")


# Mapping of allowed commands to their handler functions
_ALLOWED_COMMANDS = {
    "ls": _cmd_ls,
    "pwd": _cmd_pwd,
    "whoami": _cmd_whoami,
    "date": _cmd_date,
    "echo": _cmd_echo,
    "cat": _cmd_cat,
    "head": _cmd_head,
    "tail": _cmd_tail,
    "grep": _cmd_grep,
    "uptime": _cmd_uptime,
}


def executeCommand():
    """
    Read a command from a user input, validate it, and execute it.
    Only a predefined set of safe commands is allowed.
    Returns the command's standard output as a string.
    Raises ValueError for disallowed commands.
    """
    raw_cmd = input("Enter command: ").strip()
    if not raw_cmd:
        raise ValueError("No command provided")

    args = shlex.split(raw_cmd)

    cmd_name = args[0]
    if cmd_name not in _ALLOWED_COMMANDS:
        raise ValueError(f"Command '{cmd_name}' is not allowed")

    try:
        output = _ALLOWED_COMMANDS[cmd_name](args)
    except RuntimeError as e:
        raise RuntimeError(str(e)) from e

    return output.rstrip()

