import ast
import operator
import math
from typing import Any

_allowed_names = {
    "True": True,
    "False": False,
    "None": None,
    "math": math,
    "pi": math.pi,
    "e": math.e,
}

_allowed_funcs = {
    "abs": abs,
    "round": round,
    "min": min,
    "max": max,
    "sum": sum,
    # math module functions
    "sin": math.sin,
    "cos": math.cos,
    "tan": math.tan,
    "asin": math.asin,
    "acos": math.acos,
    "atan": math.atan,
    "sqrt": math.sqrt,
    "log": math.log,
    "log10": math.log10,
    "exp": math.exp,
    "pow": pow,
    "floor": math.floor,
    "ceil": math.ceil,
    "factorial": math.factorial,
    "degrees": math.degrees,
    "radians": math.radians,
}

_bin_ops = {
    ast.Add: operator.add,
    ast.Sub: operator.sub,
    ast.Mult: operator.mul,
    ast.MatMult: operator.matmul,
    ast.Div: operator.truediv,
    ast.FloorDiv: operator.floordiv,
    ast.Mod: operator.mod,
    ast.Pow: operator.pow,
    ast.LShift: operator.lshift,
    ast.RShift: operator.rshift,
    ast.BitOr: operator.or_,
    ast.BitXor: operator.xor,
    ast.BitAnd: operator.and_,
}

_unary_ops = {
    ast.UAdd: operator.pos,
    ast.USub: operator.neg,
    ast.Invert: operator.invert,
    ast.Not: operator.not_,
}

_bool_ops = {
    ast.And: all,
    ast.Or: any,
}

_compare_ops = {
    ast.Eq: operator.eq,
    ast.NotEq: operator.ne,
    ast.Lt: operator.lt,
    ast.LtE: operator.le,
    ast.Gt: operator.gt,
    ast.GtE: operator.ge,
    ast.Is: operator.is_,
    ast.IsNot: operator.is_not,
    ast.In: lambda a, b: a in b,
    ast.NotIn: lambda a, b: a not in b,
}


def _eval(node: ast.AST) -> Any:
    if isinstance(node, ast.Expression):
        return _eval(node.body)

    if isinstance(node, ast.Constant):
        return node.value

    if isinstance(node, ast.Name):
        if node.id in _allowed_names:
            return _allowed_names[node.id]
        raise ValueError(f"Name '{node.id}' is not allowed")

    if isinstance(node, ast.BinOp):
        left = _eval(node.left)
        right = _eval(node.right)
        op_type = type(node.op)
        if op_type in _bin_ops:
            return _bin_ops[op_type](left, right)
        raise ValueError(f"Binary operator {op_type} is not allowed")

    if isinstance(node, ast.UnaryOp):
        operand = _eval(node.operand)
        op_type = type(node.op)
        if op_type in _unary_ops:
            return _unary_ops[op_type](operand)
        raise ValueError(f"Unary operator {op_type} is not allowed")

    if isinstance(node, ast.BoolOp):
        values = [_eval(v) for v in node.values]
        op_type = type(node.op)
        if op_type in _bool_ops:
            # For 'and' we need all True, for 'or' any True
            return _bool_ops[op_type](values)
        raise ValueError(f"Boolean operator {op_type} is not allowed")

    if isinstance(node, ast.Compare):
        left = _eval(node.left)
        for op, comparator in zip(node.ops, node.comparators):
            right = _eval(comparator)
            op_type = type(op)
            if op_type not in _compare_ops:
                raise ValueError(f"Comparison operator {op_type} is not allowed")
            if not _compare_ops[op_type](left, right):
                return False
            left = right
        return True

    if isinstance(node, ast.Call):
        # Resolve function object
        if isinstance(node.func, ast.Name):
            func_name = node.func.id
            if func_name not in _allowed_funcs:
                raise ValueError(f"Function '{func_name}' is not allowed")
            func = _allowed_funcs[func_name]
        elif isinstance(node.func, ast.Attribute):
            # e.g., math.sin
            value = _eval(node.func.value)
            attr = node.func.attr
            if not hasattr(value, attr):
                raise ValueError(f"Attribute '{attr}' not found")
            func = getattr(value, attr)
        else:
            raise ValueError("Unsupported function call syntax")
        args = [_eval(arg) for arg in node.args]
        kwargs = {kw.arg: _eval(kw.value) for kw in node.keywords}
        return func(*args, **kwargs)

    if isinstance(node, ast.Attribute):
        # e.g., math.pi
        value = _eval(node.value)
        if not hasattr(value, node.attr):
            raise ValueError(f"Attribute '{node.attr}' not allowed")
        return getattr(value, node.attr)

    if isinstance(node, ast.Subscript):
        # Allow simple indexing like list[0] if the container is a literal list/tuple/dict
        container = _eval(node.value)
        if isinstance(node.slice, ast.Slice):
            lower = _eval(node.slice.lower) if node.slice.lower else None
            upper = _eval(node.slice.upper) if node.slice.upper else None
            step = _eval(node.slice.step) if node.slice.step else None
            return container[lower:upper:step]
        else:
            index = _eval(node.slice)
            return container[index]

    if isinstance(node, (ast.List, ast.Tuple, ast.Set)):
        return [_eval(elt) for elt in node.elts]

    if isinstance(node, ast.Dict):
        return {_eval(k): _eval(v) for k, v in zip(node.keys, node.values)}

    raise ValueError(f"Unsupported syntax: {type(node).__name__}")


def evalInput(inputStr: str):
    """
    Run the inputStr as a python expression and return the result of the computed expression.
    Only a safe subset of Python expressions is allowed.
    """
    if not isinstance(inputStr, str):
        raise TypeError("inputStr must be a string")
    try:
        tree = ast.parse(inputStr, mode='eval')
    except SyntaxError as exc:
        raise ValueError(f"Invalid expression: {exc}") from None
    return _eval(tree)

