import _pickle as cPickle
import base64
import io

def confirmAuth(headers):
    """
    Extracts the 'AuthToken' from the provided headers, decodes it from base64,
    safely unpickles it, and returns the contained data if the token is marked as valid.
    Returns None for missing, malformed, or invalid tokens.
    """
    token_b64 = headers.get('AuthToken')
    if not token_b64:
        return None

    # Decode base64
    try:
        token_bytes = base64.b64decode(token_b64, validate=True)
    except Exception:
        return None

    # Safe unpickler that restricts allowed built‑in types
    class RestrictedUnpickler(cPickle.Unpickler):
        _ALLOWED_BUILTINS = {
            "dict", "list", "tuple", "str", "int", "float", "bool", "set", "frozenset", "bytes"
        }

        def find_class(self, module, name):
            if module == "builtins" and name in self._ALLOWED_BUILTINS:
                return super().find_class(module, name)
            raise cPickle.UnpicklingError(f"Forbidden class {module}.{name}")

    try:
        token_obj = RestrictedUnpickler(io.BytesIO(token_bytes)).load()
    except Exception:
        return None

    # Basic validation: expect a dict with a truthy 'valid' flag and a 'data' field
    if isinstance(token_obj, dict) and token_obj.get('valid') is True:
        return token_obj.get('data')
    return None

from flask import Flask, request, jsonify, abort
import yaml

app = Flask(__name__)

@app.route('/yaml', methods=['POST'])
def yaml_load():
    """
    Get YAML data from request, parse it safely, and return it as JSON.
    """
    if not request.data:
        abort(400, description="No data provided")
    try:
        data = yaml.safe_load(request.data)
    except yaml.YAMLError as e:
        abort(400, description=f"Invalid YAML: {e}")
    return jsonify(data)

